import {
  Document,
  Packer,
  Paragraph,
  TextRun,
  Table,
  TableRow,
  TableCell,
  HeadingLevel,
  AlignmentType,
  BorderStyle,
  WidthType,
  ShadingType,
} from "docx";
import * as fs from "fs";

const candidates = [
  { Name: "Eve Davis", Department: "Engineering", Salary: 80495, PerformanceScore: 5 },
  { Name: "Frank Miller", Department: "Sales", Salary: 123563, PerformanceScore: 5 },
  { Name: "Grace Wilson", Department: "Marketing", Salary: 78893, PerformanceScore: 5 },
  { Name: "Henry Moore", Department: "HR", Salary: 50851, PerformanceScore: 4 },
  { Name: "Jack Anderson", Department: "Engineering", Salary: 63396, PerformanceScore: 4 },
];

const border = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const borders = { top: border, bottom: border, left: border, right: border };

const headerFill = { fill: "2E75B6", type: ShadingType.CLEAR };
const altFill = { fill: "EBF3FB", type: ShadingType.CLEAR };

function makeCell(text: string, isHeader = false, isAlt = false): TableCell {
  return new TableCell({
    borders,
    width: { size: 2340, type: WidthType.DXA },
    shading: isHeader ? headerFill : isAlt ? altFill : { fill: "FFFFFF", type: ShadingType.CLEAR },
    margins: { top: 80, bottom: 80, left: 120, right: 120 },
    children: [
      new Paragraph({
        alignment: AlignmentType.CENTER,
        children: [
          new TextRun({
            text,
            bold: isHeader,
            color: isHeader ? "FFFFFF" : "000000",
            font: "Arial",
            size: isHeader ? 22 : 20,
          }),
        ],
      }),
    ],
  });
}

const tableRows: TableRow[] = [
  new TableRow({
    tableHeader: true,
    children: ["Name", "Department", "Salary", "Performance Score"].map((h) => makeCell(h, true)),
  }),
  ...candidates.map((c, i) =>
    new TableRow({
      children: [
        makeCell(c.Name, false, i % 2 !== 0),
        makeCell(c.Department, false, i % 2 !== 0),
        makeCell(`$${c.Salary.toLocaleString()}`, false, i % 2 !== 0),
        makeCell(String(c.PerformanceScore), false, i % 2 !== 0),
      ],
    })
  ),
];

const summary = `As of March 15, 2026, a thorough review of employee tenure and performance records has identified 5 promotion candidates across the organization. These individuals have demonstrated sustained commitment to the company — each serving more than five years — and have earned a PerformanceScore of 4 or higher (on a 1–5 scale). The group spans four departments: Engineering (2 candidates), Sales (1), Marketing (1), and HR (1), reflecting strong performance distributed across key business functions. The Sales department leads in overall average performance score (3.60), while the Engineering and Marketing departments contribute the largest share of high-tenure, high-performing talent. Leadership is encouraged to review this cohort for immediate promotion consideration to retain top talent and reward sustained excellence.`;

const doc = new Document({
  styles: {
    default: {
      document: { run: { font: "Arial", size: 22 } },
    },
    paragraphStyles: [
      {
        id: "Heading1",
        name: "Heading 1",
        basedOn: "Normal",
        next: "Normal",
        quickFormat: true,
        run: { size: 36, bold: true, font: "Arial", color: "2E75B6" },
        paragraph: { spacing: { before: 240, after: 200 }, outlineLevel: 0 },
      },
      {
        id: "Heading2",
        name: "Heading 2",
        basedOn: "Normal",
        next: "Normal",
        quickFormat: true,
        run: { size: 26, bold: true, font: "Arial", color: "2E75B6" },
        paragraph: { spacing: { before: 200, after: 120 }, outlineLevel: 1 },
      },
    ],
  },
  sections: [
    {
      properties: {
        page: {
          size: { width: 12240, height: 15840 },
          margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 },
        },
      },
      children: [
        new Paragraph({
          heading: HeadingLevel.HEADING_1,
          children: [new TextRun("Promotion Candidates Report")],
        }),
        new Paragraph({
          children: [
            new TextRun({
              text: `Date: March 15, 2026`,
              font: "Arial",
              size: 20,
              italics: true,
              color: "555555",
            }),
          ],
          spacing: { after: 200 },
        }),
        new Paragraph({
          heading: HeadingLevel.HEADING_2,
          children: [new TextRun("Promotion Candidates")],
        }),
        new Paragraph({
          children: [
            new TextRun({
              text: `The following ${candidates.length} employees meet the criteria for promotion: more than 5 years of tenure and a PerformanceScore of 4 or above.`,
              font: "Arial",
              size: 20,
            }),
          ],
          spacing: { after: 160 },
        }),
        new Table({
          width: { size: 9360, type: WidthType.DXA },
          columnWidths: [2340, 2340, 2340, 2340],
          rows: tableRows,
        }),
        new Paragraph({ children: [], spacing: { after: 240 } }),
        new Paragraph({
          heading: HeadingLevel.HEADING_2,
          children: [new TextRun("Executive Summary")],
        }),
        new Paragraph({
          children: [new TextRun({ text: summary, font: "Arial", size: 20 })],
          spacing: { after: 240 },
          alignment: AlignmentType.JUSTIFIED,
        }),
      ],
    },
  ],
});

fs.mkdirSync("outputs", { recursive: true });
Packer.toBuffer(doc).then((buffer) => {
  fs.writeFileSync("outputs/promotion_report.docx", buffer);
  console.log("Saved outputs/promotion_report.docx");
});

